import './base/Slider.base.scss';
import './Slider.scss';

import { classNames } from ':helpers/classnames';
import type { ChangeEventHandler, FC, ReactNode } from 'react';
import React, { useEffect, useMemo, useRef, useState } from 'react';

import { Typography } from '../Typography';
import { range } from './range';
import type { SliderProps } from './Slider.types';

export const Slider: FC<SliderProps> = ({
	min = 0,
	max = 100,
	step = 'any',
	showOptions = false,
	showLabel = false,
	value = min,
	optionsStep,
	onChange,
	className,
	options,
	startAdornment,
	endAdornment,
	disabled,
	...props
}) => {
	const [localValue, setLocalValue] = useState<number>(Math.max(value, min));
	const sliderRef = useRef<HTMLInputElement | null>(null);

	useEffect(() => {
		setLocalValue(Math.max(value, min));
	}, [value, min]);

	useEffect(() => {
		const currentSlider = sliderRef.current;

		if (currentSlider) {
			const handler = (event: unknown): void => {
				onChange?.(event as React.ChangeEvent<HTMLInputElement>);
			};
			currentSlider?.addEventListener('value_change', handler);

			return () => {
				currentSlider?.removeEventListener('value_change', handler);
			};
		}
	}, [sliderRef, onChange]);

	useEffect(() => {
		sliderRef.current?.dispatchEvent(new Event('value_change'));
	}, [localValue, sliderRef]);

	const handleChange: ChangeEventHandler<HTMLInputElement> = event => {
		setLocalValue(Number(event.target.value));
	};

	const handleOptionClick = (number: number): void => {
		if (typeof step !== 'number') {
			return;
		}

		const modulo = number % step;
		const halfStep = step / 2;

		if (modulo < halfStep) {
			setLocalValue(number - modulo);
		} else {
			setLocalValue(number + modulo);
		}
	};

	const targetOptions = useMemo(
		() => options || range(min, max, optionsStep || step),
		[min, max, step, optionsStep, options],
	);

	const marginLeft = useMemo(() => ((localValue - min) * 100) / (max - min), [localValue, min, max]);

	const backgroundSize = useMemo(() => (Number(localValue) * 100) / Number(max), [localValue, max]);

	return (
		<div
			data-testid="Slider"
			className={classNames('dsb_slider-container', className, disabled && 'dsb_slider-container__disabled')}
			aria-valuemax={max}
			aria-valuemin={min}
			aria-valuenow={value}
			aria-live="polite"
		>
			{startAdornment && (
				<div
					className={classNames(
						'dsb_slider-adornment',
						'dsb_slider-adornment--start',
						'dsb_slider-adornment--left',
						`dsb_slider-adornment--${startAdornment.position}`,
					)}
				>
					{startAdornment.content}
				</div>
			)}

			{endAdornment && (
				<div
					className={classNames(
						'dsb_slider-adornment',
						'dsb_slider-adornment--end',
						'dsb_slider-adornment--right',
						`dsb_slider-adornment--${endAdornment.position}`,
					)}
				>
					{endAdornment.content}
				</div>
			)}

			{showLabel && !disabled && (
				<div className="dsb_slider-value-track">
					<div style={{ marginLeft: `${marginLeft}%` }} className="dsb_slider-value-label-wrapper">
						<Typography variant="caption" className="dsb_slider-value-label">
							{localValue}
						</Typography>
					</div>
				</div>
			)}

			<input
				{...props}
				ref={sliderRef}
				value={localValue}
				min={min}
				max={max}
				step={step}
				type="range"
				style={{
					backgroundSize: `${backgroundSize}% 100%`,
				}}
				onChange={handleChange}
				className="dsb_slider"
				disabled={disabled}
			/>

			{showOptions && (
				<div className="dsb_slider-datalist">
					{targetOptions.map((number): ReactNode => {
						const isActive = number <= localValue;

						return (
							<Typography
								variant={isActive ? 'subtitle3' : 'body3'}
								key={number}
								onClick={(): void => handleOptionClick(number)}
								data-value={number}
								className={classNames(
									'dsb_slider-option dsb_slider-option__fill',
									isActive && 'dsb_slider-option__active',
								)}
							>
								{number}
							</Typography>
						);
					})}
				</div>
			)}
		</div>
	);
};
